import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { Invoice } from '../../core/models';

/**
 * Printable invoice — minimal HTML layout with @media print CSS and a Print
 * button (no PDF library). service_agent wires getInvoice(id).
 */
@Component({
  selector: 'app-invoice-print',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './invoice-print.component.html',
  styleUrl: './invoice-print.component.css',
})
export class InvoicePrintComponent implements OnInit {
  readonly loading = signal(false);
  id = '';

  readonly invoice = signal<Invoice>({
    id: 'inv1',
    salesOrderId: 'so4',
    status: 'open',
    issuedAt: '2026-07-10T00:00:00Z',
    paidAt: null,
    customer: { id: 'c1', name: 'Northwind Traders', email: 'orders@northwind.example', phone: '+1 202 555 0180' },
    lines: [
      { id: 'il1', invoiceId: 'inv1', productId: 'p1', description: 'Widget', qty: 30, unitPriceCents: 999 },
    ],
    totalCents: 29970,
  });

  readonly totalCents = computed(() =>
    (this.invoice().lines ?? []).reduce((s, l) => s + l.qty * l.unitPriceCents, 0),
  );

  constructor(private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.id = this.route.snapshot.paramMap.get('id') ?? '';
    // service_agent: this.invoice.set(await ApiService.getInvoice(this.id)).
  }

  money(cents: number): string {
    return (cents / 100).toLocaleString(undefined, { style: 'currency', currency: 'USD' });
  }

  print(): void {
    window.print();
  }
}
